SELECT species_id, SUM(estimated_population) AS total_breeding_pairs
FROM breeding_pairs
GROUP BY species_id;

SELECT AVG(b.estimated_population) AS average_estimated_population
FROM breeding_pairs b
WHERE b.estimated_population > (
    SELECT AVG(estimated_population)
    FROM breeding_pairs
);

SELECT species_name
FROM species
WHERE species_id = 1;

SELECT COUNT(*) AS conservation_status_count
FROM conservation_quality
WHERE species_id = 1;

SELECT estimated_population, source
FROM breeding_pairs
WHERE quality > 1;
